<script setup lang="ts">
import { computed, ref } from 'vue'; import PageHeader from '../components/PageHeader.vue'; import FeatureCard from '../components/FeatureCard.vue'
const props=defineProps<{module:'models'|'reports'|'updates'}>(); const status=ref('idle')
const data=computed(()=>({models:{eyebrow:'Model Manager',title:'Verified model registry',subtitle:'Install, hash-verify and benchmark model artifacts without treating remote registry data as executable code.',icon:'mdi-cube-outline'},reports:{eyebrow:'Report Library',title:'Documents and evidence exports',subtitle:'Browse Atlas snapshots, editable documents, PDFs and reproducibility manifests.',icon:'mdi-file-chart-outline'},updates:{eyebrow:'Update Center',title:'Signed updates and recovery',subtitle:'Check online updates, import offline packages and preserve settings through transactional migrations.',icon:'mdi-update'}}[props.module]))
async function check(){ status.value='checking'; const result=await window.mel.updater.check(); status.value=result.status+(result.version?` · ${result.version}`:'') }
</script>
<template><div class="page-wrap"><PageHeader :eyebrow="data.eyebrow" :title="data.title" :subtitle="data.subtitle" :icon="data.icon"/><v-row><v-col cols="12" md="6"><FeatureCard :title="module==='models'?'Artifact rights gate':module==='reports'?'Deterministic manifests':'Migration-safe updates'" :subtitle="module==='models'?'Unknown redistribution rights default to do not distribute.':module==='reports'?'Every export records source, template and output hashes.':'A backup is created before persistent schema changes.'" :icon="module==='models'?'mdi-license':module==='reports'?'mdi-fingerprint':'mdi-backup-restore'" color="primary"/></v-col><v-col cols="12" md="6"><v-card class="glass pa-6 h-100"><template v-if="module==='updates'"><v-btn color="primary" prepend-icon="mdi-cloud-download-outline" @click="check">Check for updates</v-btn><div class="mt-4 text-medium-emphasis">{{ status }}</div></template><template v-else><v-icon :icon="data.icon" color="secondary" size="64"/><div class="text-h6 mt-4">The repository layer is ready for indexed records.</div><p class="text-medium-emphasis">Content appears as verified jobs produce model or report manifests.</p></template></v-card></v-col></v-row></div></template>
